"use client";

import React from "react";
import { Hero2 } from "./hero";
import { DemoLayout } from "@/components/demo-layout";

export default function Hero2Page() {
  return (
    <div className="w-full bg-background text-foreground selection:bg-primary selection:text-primary-foreground font-sans">
      <Hero2 />
    </div>
  );
}

"use client";

import {
  Layout,
  Zap,
  Palette,
  Search,
  Check,
  Code2,
  MousePointer2,
  Sparkles,
  Layers,
  Cpu,
  Fingerprint
} from "lucide-react";
import { cn } from "@/lib/utils";

const icons = [
  { icon: Layout, rotate: "-10deg", y: 0, zIndex: 10 },
  { icon: Zap, rotate: "-8deg", y: -10, zIndex: 11 },
  { icon: Palette, rotate: "-6deg", y: -20, zIndex: 12 },
  { icon: Search, rotate: "-4deg", y: -10, zIndex: 13 },
  { icon: Code2, rotate: "-2deg", y: 0, zIndex: 14 },
  { icon: Check, rotate: "0deg", y: 15, zIndex: 20, isCenter: true },
  { icon: MousePointer2, rotate: "2deg", y: 0, zIndex: 14 },
  { icon: Sparkles, rotate: "4deg", y: -10, zIndex: 13 },
  { icon: Layers, rotate: "6deg", y: -20, zIndex: 12 },
  { icon: Cpu, rotate: "8deg", y: -10, zIndex: 11 },
  { icon: Fingerprint, rotate: "10deg", y: 0, zIndex: 10 },
];

export function FeaturedIcons({ className }: { className?: string }) {
  return (
    <div className={cn("mt-16 mb-24 flex items-center justify-center gap-2 sm:gap-4 lg:gap-6", className)}>
      {icons.map((item, i) => (
        <div
          key={i}
          className={cn(
            "relative flex items-center justify-center border border-border shadow-xl transition-all duration-300",
            item.isCenter
              ? "size-24 sm:size-28 z-20 shadow-black/30 dark:shadow-white/20 rounded-[32px] bg-foreground text-background"
              : "size-16 sm:size-20 rounded-[20px] bg-card text-muted-foreground"
          )}
          style={{
            zIndex: item.zIndex,
            transform: `translateY(${item.y}px) rotate(${item.rotate}) ${item.isCenter ? 'scale(0.9)' : ''}`
          }}
        >
          <item.icon
            className={cn(item.isCenter ? "size-8 sm:size-10" : "size-5 sm:size-6")}
            strokeWidth={item.isCenter ? 2.5 : 2}
          />
        </div>
      ))}
    </div>
  );
}

import React from "react";
import { cn } from "@/lib/utils";

export function BorderSeparator({
  children,
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      aria-hidden="true"
      className={cn(
        "-translate-x-1/2 pointer-events-none absolute left-1/2 w-screen border-t border-dashed",
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}

export function DashedLines({
  width = 20,
  height = 50,
  x = 10,
  className,
  ...props
}: React.ComponentProps<"svg">) {
  const id = React.useId();

  return (
    <svg
      aria-hidden="true"
      className={cn("pointer-events-none size-full stroke-border", className)}
      {...props}
    >
      <pattern
        height={height}
        id={id}
        patternUnits="userSpaceOnUse"
        width={width}
        x={x}
      >
        <path d={`M.5 0 V${height}`} fill="none" strokeDasharray={2.5} />
      </pattern>
      <rect fill={`url(#${id})`} height="100%" strokeWidth={0} width="100%" />
    </svg>
  );
}

export function GridPattern({
  width = 40,
  height = 40,
  x = -1,
  y = -1,
  strokeDasharray = "0",
  className,
  ...props
}: React.ComponentProps<"svg"> & {
  width?: number;
  height?: number;
  x?: number;
  y?: number;
  strokeDasharray?: string;
}) {
  const id = React.useId();

  return (
    <svg
      aria-hidden="true"
      className={cn(
        "pointer-events-none absolute inset-0 h-full w-full fill-transparent stroke-border/30",
        className
      )}
      {...props}
    >
      <defs>
        <pattern
          id={id}
          width={width}
          height={height}
          patternUnits="userSpaceOnUse"
          x={x}
          y={y}
        >
          <path
            d={`M.5 ${height}V.5H${width}`}
            fill="none"
            strokeDasharray={strokeDasharray}
          />
        </pattern>
      </defs>
      <rect width="100%" height="100%" strokeWidth={0} fill={`url(#${id})`} />
    </svg>
  );
}

export function GlassCard({
  children,
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "glass-card p-6 rounded-xl",
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}
